    eco: string;
    name: string;
  };
  moves: object[];
  clocks: number[];
  analysis?: Analysis[];
}

interface Analysis {
  eval?: number;
  mate?: number;
  best?: string;
  variation?: string;
  judgment?: {
    name: string;
    comment: string;
  };
}

export type GameCallback = (game: Game) => void;

