import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';
import { OAuth2AuthCodePKCE } from '@bity/oauth2-auth-code-pkce';
import { ChessFetchService } from '@services/chess-fetch.service';

const LICHESS_HOST = 'https://lichess.org';
const CLIENT_ID = 'http://localhost:4200/';
const STORAGE_KEY_TOKEN = 'lichessToken';
const STORAGE_KEY_USERNAME = 'lichessUsername';

@Injectable({
  providedIn: 'root',
})
export class LichessAuthService {
  private router = inject(Router);
  private fetchService = inject(ChessFetchService);
  private http = inject(HttpClient);

  private oauth = new OAuth2AuthCodePKCE({
    authorizationUrl: `${LICHESS_HOST}/oauth`,
    tokenUrl: `${LICHESS_HOST}/api/token`,
    clientId: CLIENT_ID,
    scopes: [],
    redirectUrl: window.location.href.split('?')[0],
    onAccessTokenExpiry: (refreshAccessToken) => refreshAccessToken(),
    onInvalidGrant: () => {
      // placeholder - tokens cannot be refreshed
    },
  });

  public isLoggedIn(): boolean {
    return !!localStorage.getItem(STORAGE_KEY_TOKEN);
  }

  public getUsername(): string {
    return localStorage.getItem(STORAGE_KEY_USERNAME) ?? '';
  }

  public async init(): Promise<void> {
    const token = localStorage.getItem(STORAGE_KEY_TOKEN);
    if (token) {
      this.fetchService.addLichessOauthToken(token);
    }

    try {
      const isReturning = await this.oauth.isReturningFromAuthServer();
      if (isReturning) {
        const accessContext = await this.oauth.getAccessToken();
        const token = accessContext.token?.value;
        if (token) {
          localStorage.setItem(STORAGE_KEY_TOKEN, token);
          this.fetchService.addLichessOauthToken(token);
          await this.fetchUsername(token);
          this.router.navigate(['/']);
        }
      }
    } catch {
      // User cancelled or error
    }
  }

  public async login(): Promise<void> {
    await this.oauth.fetchAuthorizationCode();
  }

  public async logout(): Promise<void> {
    const token = localStorage.getItem(STORAGE_KEY_TOKEN);
    if (token) {
      try {
        await firstValueFrom(
          this.http.delete(`${LICHESS_HOST}/api/token`, {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }),
        );
      } catch {
        // Ignore
      }
    }
    localStorage.removeItem(STORAGE_KEY_TOKEN);
    localStorage.removeItem(STORAGE_KEY_USERNAME);
    this.fetchService.resetOauthToken();
    window.location.href = '/';
  }

  private async fetchUsername(token: string): Promise<void> {
    const account = await firstValueFrom(
      this.http.get<{ username: string }>(`${LICHESS_HOST}/api/account`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      }),
    );
    if (account) {
      localStorage.setItem(STORAGE_KEY_USERNAME, account.username);
    }
  }
}

import { inject, Injectable } from '@angular/core';
import { parseGame } from '@mliebelt/pgn-parser';
import { ChessFetchService } from '@services/chess-fetch.service';
import {
  Game,
  GameCallback,
  LichessGameParameters,
  Profile,
  Tournament,
  LichessGame,
  LichessArena,
  LichessSwiss,
  LichessPlayer,
  ChessColor,
  TimeControl,
  Result,
  NetworkError,
} from '@model';

@Injectable({
  providedIn: 'root',
})
export class LichessService {
  private readonly fetchService = inject(ChessFetchService);

  public qs(obj: Record<string, unknown>): string {
    const params = new URLSearchParams(obj as Record<string, string>).toString();
    return params ? '?' + params : '';
  }

  public async profile(username: string): Promise<Profile> {
    const response = await this.fetchService.fetchFromEndpoint(
      `https://lichess.org/api/user/${username}`,
    );
    this.fetchService.checkForServerError(response);
    const data = await response.json();
    return this.formatProfile(data);
  }

  public async arena(id: string): Promise<Tournament> {
    return this.tournament(`https://lichess.org/api/tournament/${id}`);
  }

  public async swiss(id: string): Promise<Tournament> {
    return this.tournament(`https://lichess.org/api/swiss/${id}`);
  }

  private async tournament(url: string): Promise<Tournament> {
    const response = await this.fetchService.fetchFromEndpoint(url);
    this.fetchService.checkForServerError(response);
    const data = await response.json();
    return this.formatTournament(data);
  }

  public async playerGames(
    username: string,
    callback: GameCallback,
    params: LichessGameParameters = {},
  ): Promise<void> {
    return this.games(`https://lichess.org/api/games/user/${username}`, callback, params);
  }

  public async arenaGames(
    id: string,
    callback: GameCallback,
    params: LichessGameParameters = {},
  ): Promise<void> {
    return this.games(`https://lichess.org/api/tournament/${id}/games`, callback, params);
  }

  public async swissGames(
    id: string,
    callback: GameCallback,
    params: LichessGameParameters = {},
  ): Promise<void> {
    return this.games(`https://lichess.org/api/swiss/${id}/games`, callback, params);
  }

  public async games(
    url: string,
    callback: GameCallback,
    params: LichessGameParameters = {},
  ): Promise<void> {
    const response = await this.fetchService.fetchFromEndpoint(
      url + this.qs(params as Record<string, unknown>),
      {
        headers: {
          Accept: 'application/x-ndjson',
        },
      },
    );

    this.fetchService.checkForServerError(response);

    if (!response.body) throw new NetworkError('Response body is null');
    const reader = response.body.getReader();
    const decoder = new TextDecoder();

    while (true) {
      const { done, value } = await reader.read();
      if (done) return;

      const chunk = decoder.decode(value, { stream: true });
      const lines = chunk.split('\n').filter((line) => line.trim());

      for (const line of lines) {
        try {
          const data = JSON.parse(line);
          callback(this.formatGame(data));
        } catch {
          // Skip invalid JSON lines
        }
      }
    }
  }

  public async teamMembers(teamId: string, callback: (player: Profile) => void): Promise<void> {
    const response = await this.fetchService.fetchFromEndpoint(
      `https://lichess.org/api/team/${teamId}/users`,
      {
        headers: {
          Accept: 'application/x-ndjson',
        },
      },
    );

    this.fetchService.checkForServerError(response);

    if (!response.body) throw new NetworkError('Response body is null');
    const reader = response.body.getReader();
    const decoder = new TextDecoder();

    while (true) {
      const { done, value } = await reader.read();
      if (done) return;

      const chunk = decoder.decode(value, { stream: true });
      const lines = chunk.split('\n').filter((line) => line.trim());

      for (const line of lines) {
        try {
          const data = JSON.parse(line);
          callback(this.formatProfile(data));
        } catch {
          // Skip invalid JSON lines
        }
      }
    }
  }

  public async game(url: string): Promise<Game> {
    const gameId = new URL(url).pathname.split('/')[1];

    let normalizedGameId = gameId;
    if (gameId.length === 12) {
      normalizedGameId = gameId.substring(0, 8);
    }

    if (normalizedGameId.length !== 8) {
      throw new Error(`Invalid game ID: ${normalizedGameId}`);
    }

    const response = await this.fetchService.fetchFromEndpoint(
      `https://lichess.org/game/export/${normalizedGameId}${this.qs({ pgnInJson: true, clocks: true })}`,
    );
    this.fetchService.checkForServerError(response);
    const data = await response.json();
    return this.formatGame(data);
  }

  private formatTournament(json: LichessArena | LichessSwiss): Tournament {
    if ('nbRounds' in json) {
      return {
        id: json.id,
        type: 'swiss',
        site: 'lichess',
        url: `https://lichess.org/swiss/${json.id}`,
        name: json.name,
        timeControl: {
          initial: json.clock.limit,
          increment: json.clock.increment,
        },
        isFinished: json.status === 'finished',
        playerCount: json.nbPlayers,
        stats: {
          games: json.stats.games,
        },
      };
    }

    return {
      id: json.id,
      type: 'arena',
      site: 'lichess',
      url: `https://lichess.org/tournament/${json.id}`,
      name: json.fullName,
      timeControl: {
        initial: json.clock.limit,
        increment: json.clock.increment,
      },
      isFinished: json.isFinished,
      playerCount: json.nbPlayers,
      stats: {
        games: json.stats.games,
      },
    };
  }

  private formatGame(json: LichessGame): Game {
    const parsedMoves =
      json.variant === 'standard' && json.moves
        ? parseGame(json.pgn ?? json.moves, { startRule: 'game' }).moves
        : [];

    return {
      site: 'lichess',
      type: 'game',
      id: json.id,
      links: {
        white: `https://lichess.org/${json.id}`,
        black: `https://lichess.org/${json.id}/black`,
      },
      timestamp: json.createdAt,
      lastMoveAt: json.lastMoveAt,
      isStandard: json.variant === 'standard',
      players: {
        white: {
          username: json.players.white.user?.name,
          title: json.players.white.user?.title ?? null,
          rating: json.players.white.rating,
        },
        black: {
          username: json.players.black.user?.name,
          title: json.players.black.user?.title ?? null,
          rating: json.players.black.rating,
        },
      },
      timeControl: this.getTimeControl(json.clock),
      result: this.getResult(json),
      opening: {
        name: json.opening?.name ?? '',
        eco: json.opening?.eco ?? '',
      },
      moves: parsedMoves,
      clocks: json.clocks ?? [],
      analysis: json.analysis ?? [],
    };
  }

  private getResult(json: Partial<LichessGame>): Result {
    switch (json.status) {
      case 'mate':
        return {
          winner: json.winner,
          via: 'checkmate',
          label: this.getResultStringForColor(json.winner),
        };
      case 'resign':
        return {
          winner: json.winner,
          via: 'resignation',
          label: this.getResultStringForColor(json.winner),
        };
      case 'outoftime':
        return {
          winner: json.winner,
          via: 'timeout',
          label: this.getResultStringForColor(json.winner),
        };
      case 'timeout':
        return {
          winner: json.winner,
          via: 'abandonment',
          label: this.getResultStringForColor(json.winner),
        };
      case 'noStart':
        return {
          winner: json.winner,
          via: 'noStart',
          label: this.getResultStringForColor(json.winner),
        };
      case 'variantEnd':
        return {
          winner: json.winner,
          via: 'variant',
          label: this.getResultStringForColor(json.winner),
        };
      case 'cheat':
        return {
          winner: json.winner,
          via: 'cheat',
          label: this.getResultStringForColor(json.winner),
        };
      case 'draw':
        return { outcome: 'draw', label: '½-½' };
      case 'insufficientMaterialClaim':
        return { outcome: 'draw', via: 'insufficient', label: '½-½' };
      case 'stalemate':
        return { outcome: 'draw', via: 'stalemate', label: '½-½' };
    }

    throw new Error(`Unexpected result: ${json.status}`);
  }

  private getTimeControl(timeControl?: { initial: number; increment: number }): TimeControl {
    if (!timeControl) {
      return { initial: 0, increment: 0 };
    }

    return {
      initial: timeControl.initial,
      increment: timeControl.increment,
    };
  }

  private formatProfile(player: LichessPlayer): Profile {
    if (player.disabled) {
      return {
        site: 'lichess',
        type: 'profile',
        username: player.username,
        link: `https://lichess.org/@/${player.username}`,
        disabled: true,
      };
    }

    const name = [player.profile?.firstName, player.profile?.lastName].join(' ').trim();

    return {
      site: 'lichess',
      type: 'profile',
      link: player.url,
      username: player.username,
      title: player.title ?? '',
      createdAt: player.createdAt,
      lastSeenAt: player.seenAt,
      name,
      location: player.profile?.location ?? '',
      ratings: {
        bullet: {
          rating: player.perfs.bullet.rating,
          games: player.perfs.bullet.games,
        },
        blitz: {
          rating: player.perfs.blitz.rating,
          games: player.perfs.blitz.games,
        },
        rapid: {
          rating: player.perfs.rapid.rating,
          games: player.perfs.rapid.games,
        },
      },
      counts: player.count?.all ? { all: player.count.all } : {},
      marked: player.tosViolation ?? false,
    };
  }

  private getResultStringForColor(color?: ChessColor): '1-0' | '0-1' | '½-½' {
    if (color === 'white') return '1-0';
    if (color === 'black') return '0-1';
    return '½-½';
  }
}

import { inject, Injectable, signal } from '@angular/core';
import { ChessFetchService } from '@services/chess-fetch.service';
import type {
  BookApiResponse,
  BookMovesData,
  MoveStats,
  OpeningBookConfig,
} from '@model/opening-explorer.model';
import { DEFAULT_BOOK_CONFIG } from '@model/opening-explorer.model';

@Injectable({ providedIn: 'root' })
export class OpeningBookService {
  private fetchService = inject(ChessFetchService);
  private cache = new Map<string, BookMovesData>();
  private lastOpeningName: string | undefined = undefined;

  public readonly config = signal<OpeningBookConfig>(DEFAULT_BOOK_CONFIG);

  public updateConfig(config: OpeningBookConfig): void {
    this.config.set(config);
    this.clearCache();
  }

  public async fetchBookMoves(fen: string): Promise<BookMovesData> {
    const cfg = this.config();
    if (cfg.bookType === 'off') {
      return { fetch: 'off' };
    }
    const cached = this.cache.get(fen);
    if (cached) return cached;

    const pending: BookMovesData = { fetch: 'pending' };
    this.cache.set(fen, pending);

    try {
      const encoded = encodeURIComponent(fen);
      const ratings = cfg.ratings.join(',');
      const speeds = cfg.speeds.join(',');
      const url = `https://explorer.lichess.ovh/${cfg.bookType}?fen=${encoded}&variant=standard&ratings=${ratings}&speeds=${speeds}`;

      const response = await this.fetchService.fetchFromEndpoint(url, {
        headers: { 'User-Agent': 'chess-app/1.0' },
      });
      this.fetchService.checkForServerError(response);
      const data: BookApiResponse = await response.json();

      const openingName = data.opening
        ? `${data.opening.eco} ${data.opening.name}`
        : this.lastOpeningName;
      this.lastOpeningName = openingName;
      const transformed: BookMovesData = {
        fetch: 'success',
        openingName,
        moves: (data.moves ?? []).map((m) => {
          const count = m.white + m.black + m.draws;
          const details: MoveStats = {
            hasData: true,
            whiteWins: m.white,
            blackWins: m.black,
            draws: m.draws,
            count,
            totalOpponentElo: m.averageRating * count,
            averageElo: m.averageRating,
          };
          return {
            san: m.san,
            details,
            moveCount: count,
          };
        }),
      };
      this.cache.set(fen, transformed);
      return transformed;
    } catch {
      const failed: BookMovesData = { fetch: 'failed' };
      this.cache.set(fen, failed);
      return failed;
    }
  }

  public clearCache(): void {
    this.cache.clear();
    this.lastOpeningName = undefined;
  }
}

import { Injectable } from '@angular/core';
import { Chess } from 'chess.js';
import type { Game } from '@model';
import type { MoveStats, PgnStats, ExplorerMove } from '@model/opening-explorer.model';

function simplifiedFen(fen: string): string {
  const parts = fen.split(' ');
  if (parts.length <= 4) return fen;
  return `${parts[0]} ${parts[1]} ${parts[2]}`;
}

function emptyStats(): MoveStats {
  return {
    hasData: false,
    count: 0,
    blackWins: 0,
    whiteWins: 0,
    draws: 0,
    totalOpponentElo: 0,
  };
}

interface GraphNode {
  fen: string;
  playedBy: Map<string, number>;
  playedByMax: number;
  details: number | MoveStats;
  gameResults: number[];
}

@Injectable({ providedIn: 'root' })
export class OpeningGraphService {
  private nodes = new Map<string, GraphNode>();
  private bookCache = new Map<string, unknown>();
  public pgnStats: PgnStats[] = [];
  public playerColor: string = '';
  public hasMoves = false;

  public clear(): void {
    this.nodes = new Map<string, GraphNode>();
    this.bookCache = new Map<string, unknown>();
    this.pgnStats = [];
    this.playerColor = '';
    this.hasMoves = false;
  }

  public clearBookNodes(): void {
    this.bookCache = new Map<string, unknown>();
  }

  public addGame(game: Game, playerColor: string): void {
    const chess = new Chess();
    const rawMoves = game.moves as unknown as { notation: { notation: string } }[];
    if (!rawMoves || rawMoves.length < 2) return;

    const resultStr = game.result.label;
    const whiteName = game.players.white.username ?? '';
    const blackName = game.players.black.username ?? '';
    const isWhite = playerColor === 'white';

    const pgnStats: PgnStats = {
      result: resultStr,
      white: whiteName,
      black: blackName,
      whiteElo: game.players.white.rating ?? 0,
      blackElo: game.players.black.rating ?? 0,
      url: isWhite ? game.links.white : game.links.black,
      numberOfPlys: rawMoves.length,
    };
    pgnStats.index = this.pgnStats.length;
    this.pgnStats.push(pgnStats);
    this.playerColor = playerColor;
    this.hasMoves = true;

    for (const element of rawMoves) {
      const san = element.notation?.notation;
      if (!san) continue;
      const sourceFen = chess.fen();
      const move = chess.move(san, { strict: false });
      if (!move) continue;
      const targetFen = chess.fen();
      this.addMoveForFen(sourceFen, targetFen, move.san, pgnStats);
    }
    const lastFen = chess.fen();
    this.addGameResultOnFen(lastFen, pgnStats.index!);
    this.addStatsToRoot(pgnStats);
  }

  private addGameResultOnFen(fullFen: string, resultIndex: number): void {
    const node = this.getNode(fullFen, true);
    if (!node.gameResults) node.gameResults = [];
    node.gameResults.push(resultIndex);
  }

  private addStatsToRoot(pgnStats: PgnStats): void {
    const fen = 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1';
    const targetNode = this.getNode(fen, true);
    if (!targetNode.details || typeof targetNode.details !== 'object') {
      targetNode.details = { ...emptyStats() };
    }
    targetNode.details = this.mergeStats(targetNode.details as MoveStats, pgnStats);
  }

  private addMoveForFen(
    fullSourceFen: string,
    fullTargetFen: string,
    moveSan: string,
    resultObject: PgnStats,
  ): void {
    const targetNode = this.getNode(fullTargetFen, true);
    const existing = targetNode.details;
    targetNode.details =
      typeof existing === 'object' && existing
        ? this.mergeStats(existing as MoveStats, resultObject)
        : (resultObject.index as unknown as MoveStats);

    const sourceNode = this.getNode(fullSourceFen, true);
    if (!sourceNode.playedBy) sourceNode.playedBy = new Map();
    const current = sourceNode.playedBy.get(moveSan) ?? 0;
    sourceNode.playedBy.set(moveSan, current + 1);
    sourceNode.playedByMax = Math.max(sourceNode.playedByMax, current + 1);
  }

  private mergeStats(stats: MoveStats, resultObject: PgnStats): MoveStats {
    const resultStr = resultObject.result;
    const playerColor = this.playerColor;

    let whiteInc = 0,
      blackInc = 0,
      drawInc = 0;
    if (resultStr === '1-0') {
      whiteInc = 1;
    } else if (resultStr === '0-1') {
      blackInc = 1;
    } else {
      drawInc = 1;
    }

    const opponentElo = playerColor === 'white' ? resultObject.blackElo : resultObject.whiteElo;

    return {
      whiteWins: stats.whiteWins + whiteInc,
      blackWins: stats.blackWins + blackInc,
      draws: stats.draws + drawInc,
      count: stats.count + 1,
      totalOpponentElo: stats.totalOpponentElo + (opponentElo || 0),
      hasData: true,
    };
  }

  public getDetailsForFen(fullFen: string): MoveStats {
    const fen = simplifiedFen(fullFen);
    const node = this.nodes.get(fen);
    const details = node?.details;
    if (!details) return emptyStats();
    if (typeof details === 'number') {
      const idx = details as number;
      const pg = this.pgnStats[idx];
      if (!pg) return emptyStats();
      const merged = this.mergeStats(emptyStats(), pg);
      merged.count = merged.whiteWins + merged.blackWins + merged.draws;
      return merged;
    }
    const ms = details as MoveStats;
    ms.count = ms.whiteWins + ms.blackWins + ms.draws;
    return ms;
  }

  public movesForFen(fullFen: string): ExplorerMove[] | null {
    const fen = simplifiedFen(fullFen);
    const node = this.nodes.get(fen);
    if (!node?.playedBy || node.playedBy.size === 0) return null;

    const result: ExplorerMove[] = [];
    const maxCount = node.playedByMax;
    for (const [san, count] of node.playedBy) {
      const chess = new Chess(fullFen);
      const move = chess.move(san, { strict: false });
      if (!move) continue;

      const targetDetails = this.getDetailsForFen(chess.fen());
      result.push({
        san: move.san,
        orig: move.from,
        dest: move.to,
        level: this.levelFor(count, maxCount),
        details: targetDetails,
        moveCount: count,
      });
    }
    result.sort((a, b) => {
      if (a.moveCount === b.moveCount) return b.details.count - a.details.count;
      return b.moveCount - a.moveCount;
    });
    return result;
  }

  public gameResultsForFen(fullFen: string): PgnStats[] | null {
    const fen = simplifiedFen(fullFen);
    const node = this.nodes.get(fen);
    if (node?.gameResults) {
      return node.gameResults.map((i) => this.pgnStats[i]).filter(Boolean);
    }
    return null;
  }

  private levelFor(moveCount: number, maxCount: number): number {
    if (maxCount <= 0 || moveCount / maxCount > 0.8) return 3;
    if (moveCount / maxCount > 0.3) return 2;
    return 1;
  }

  private getNode(fullFen: string, addIfNull: boolean): GraphNode {
    const fen = simplifiedFen(fullFen);
    let node = this.nodes.get(fen);
    if (!node && addIfNull) {
      node = { fen, playedBy: new Map(), playedByMax: 0, details: emptyStats(), gameResults: [] };
      this.nodes.set(fen, node);
    }
    return node!;
  }

  public getBookNode(fullFen: string): unknown {
    return this.bookCache.get(simplifiedFen(fullFen));
  }

  public addBookNode(fullFen: string, data: unknown): void {
    this.bookCache.set(simplifiedFen(fullFen), data);
  }
}

import { Injectable, signal } from '@angular/core';
import type { NavigatorPly } from '@model/opening-explorer.model';
import { Chess } from 'chess.js';

@Injectable({ providedIn: 'root' })
export class OpeningManagerService {
  private plys: NavigatorPly[] = [];
  private $currentIndex = signal(0);
  public readonly currentIndex = this.$currentIndex.asReadonly();

  constructor() {
    this.reset();
  }

  public reset(): void {
    const rootFen = new Chess().fen();
    this.plys = [{ fen: rootFen, move: null }];
    this.$currentIndex.set(0);
  }

  public fen(): string {
    return this.plys[this.$currentIndex()]?.fen ?? new Chess().fen();
  }

  public currentMove(): number {
    return Math.floor((this.$currentIndex() - 1) / 2);
  }

  public canGoForward(): boolean {
    return this.$currentIndex() < this.plys.length - 1;
  }

  public canGoBack(): boolean {
    return this.$currentIndex() > 0;
  }

  public moveForward(): NavigatorPly | null {
    if (!this.canGoForward()) return null;
    this.$currentIndex.update((i) => i + 1);
    return this.plys[this.$currentIndex()];
  }

  public moveBack(): NavigatorPly | null {
    if (!this.canGoBack()) return null;
    this.$currentIndex.update((i) => i - 1);
    return this.plys[this.$currentIndex()];
  }

  public moveTo(index: number): NavigatorPly | null {
    if (index < 0 || index >= this.plys.length) return null;
    this.$currentIndex.set(index);
    return this.plys[index];
  }

  public addPly(fen: string, move: { from: string; to: string; san: string }): NavigatorPly {
    const nextIndex = this.$currentIndex() + 1;

    if (nextIndex < this.plys.length && this.plys[nextIndex].move?.san === move.san) {
      this.$currentIndex.set(nextIndex);
      return this.plys[nextIndex];
    }

    this.plys = this.plys.slice(0, nextIndex);
    const entry: NavigatorPly = { fen, move };
    this.plys.push(entry);
    this.$currentIndex.set(this.plys.length - 1);
    return entry;
  }
}

import { inject, Injectable } from '@angular/core';
import { Meta, Title } from '@angular/platform-browser';

export interface SeoData {
  title: string;
  description: string;
  image?: string;
}

@Injectable({ providedIn: 'root' })
export class SeoService {
  private title = inject(Title);
  private meta = inject(Meta);
  private siteName = 'ChessRoot';
  private defaultImage = 'https://chessroot.app/icon.svg';

  public setSeo(data: SeoData, path: string): void {
    const fullTitle = `${data.title} — ${this.siteName}`;
    const url = `https://chessroot.app${path}`;
    const image = data.image || this.defaultImage;

    this.title.setTitle(fullTitle);

    this.meta.updateTag({ name: 'description', content: data.description });

    this.meta.updateTag({ property: 'og:title', content: fullTitle });
    this.meta.updateTag({ property: 'og:description', content: data.description });
    this.meta.updateTag({ property: 'og:image', content: image });
    this.meta.updateTag({ property: 'og:url', content: url });
    this.meta.updateTag({ property: 'og:type', content: 'website' });
    this.meta.updateTag({ property: 'og:site_name', content: this.siteName });

    this.meta.updateTag({ name: 'twitter:card', content: 'summary_large_image' });
    this.meta.updateTag({ name: 'twitter:title', content: fullTitle });
    this.meta.updateTag({ name: 'twitter:description', content: data.description });
    this.meta.updateTag({ name: 'twitter:image', content: image });

    this.setCanonical(url);
  }

  private setCanonical(url: string): void {
    const head = document.head;
    let link = head.querySelector('link[rel="canonical"]') as HTMLLinkElement | null;
    if (!link) {
      link = document.createElement('link');
      link.rel = 'canonical';
      head.appendChild(link);
    }
    link.href = url;
  }
}

