src/app/components/move-navigation/utils.defaultValue:
(plys: NavigatorPly[]): PgnMoveEntry[] => {
  const result: PgnMoveEntry[] = [];
  let current: PgnMoveEntry | null = null;
  for (let i = 1; i < plys.length; i++) {
    const ply = plys[i];
    if (!ply.move) continue;
    const isWhite = i % 2 === 1;
    if (isWhite) {
      current = { moveNumber: Math.floor(i / 2) + 1, whitePly: ply.move.san, blackPly: '' };
      result.push(current);
    } else if (current) {
      current.blackPly = ply.move.san;
    }
  }
  return result;
}

src/app/state/reducers/explorer.reducer..defaultValue:
createReducer(
  initialExplorerState,
  on(ExplorerActions.fetchBook, (state): ExplorerState => ({
    ...state,
    bookMoves: {
      fetch: 'pending',
      openingName: state.bookMoves.openingName,
    },
  })),
  on(ExplorerActions.fetchBookSuccess, (state, { bookMoves }): ExplorerState => ({
    ...state,
    bookMoves,
  })),
  on(ExplorerActions.fetchBookFailure, (state): ExplorerState => ({
    ...state,
    bookMoves: {
      fetch: 'failed',
      openingName: state.bookMoves.openingName,
    },
  })),
)

