src/app/components/moves-table/utils/sim.defaultValue:
(count: number): string => {
  if (count >= 1_000_000) return `${(count / 1_000_000).toFixed(1)}M`;
  if (count >= 10_000) return `${Math.round(count / 1_000)}k`;
  return String(count);
}

